import React, { useState } from 'react';
import AuthService from '../services/AuthService';
import { useNavigate } from 'react-router-dom';

function Register() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [role, setRole] = useState('ROLE_CANDIDATE');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    // Validation
    if (!username || !password || !confirmPassword) {
      setError('Tất cả các trường là bắt buộc');
      return;
    }

    if (password !== confirmPassword) {
      setError('Mật khẩu không trùng khớp');
      return;
    }

    if (password.length < 6) {
      setError('Mật khẩu phải ít nhất 6 ký tự');
      return;
    }

    try {
      await AuthService.register(username, password, role);
      setSuccess('Đăng ký thành công! Chuyển hướng đến trang đăng nhập...');
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Đăng ký thất bại');
    }
  };

  return (
    <div className="container auth-container">
      <div className="auth-form">
        <h2>Tạo Tài Khoản</h2>
        
        {error && <div className="alert alert-danger">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Email / Tên Tài Khoản</label>
            <input
              type="email"
              className="form-control"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Nhập email của bạn"
            />
          </div>

          <div className="form-group">
            <label>Mật Khẩu</label>
            <input
              type="password"
              className="form-control"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Nhập mật khẩu (tối thiểu 6 ký tự)"
            />
          </div>

          <div className="form-group">
            <label>Xác Nhận Mật Khẩu</label>
            <input
              type="password"
              className="form-control"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="Xác nhận mật khẩu"
            />
          </div>

          <div className="form-group">
            <label>Loại Tài Khoản</label>
            <select
              className="form-control"
              value={role}
              onChange={(e) => setRole(e.target.value)}
            >
              <option value="ROLE_CANDIDATE">Ứng Viên (Tìm Kiếm Việc)</option>
              <option value="ROLE_EMPLOYER">Nhà Tuyển Dụng (Đăng Tin)</option>
            </select>
            <small>
              {role === 'ROLE_CANDIDATE' 
                ? '📋 Tìm kiếm công việc và quản lý hồ sơ' 
                : '💼 Đăng tin tuyển dụng và quản lý ứng viên'}
            </small>
          </div>

          <button type="submit" className="btn btn-primary btn-block">Đăng Ký</button>
        </form>

        <p className="text-center">
          Đã có tài khoản? <a href="/login">Đăng nhập tại đây</a>
        </p>
      </div>
    </div>
  );
}

export default Register;
